// Shapeクラスの定義
abstract class Shape {
    String name;

    Shape(String name) {
        this.name = name;
    }

    // 抽象メソッド：サブクラスが実装する
    abstract double area();

    // 具象メソッド：そのまま継承される
    // printInfoメソッドの定義
    void printInfo() {
        System.out.println(name + "の面積: " + area());
    }
}

// Circleクラスの定義
class Circle extends Shape {
    double radius;

    Circle(double radius) {
        super("円");
        this.radius = radius;
    }

    @Override
    // areaメソッドの定義
    double area() {
        return Math.PI * radius * radius;
    }
}

// Mainクラスの定義
public class Main {
    public static void main(String[] args) {
        // Shape s = new Shape("図形"); // コンパイルエラー！
        Shape s = new Circle(5.0);
        s.printInfo();  // 円の面積: 78.53981633974483
    }
}

