// Beverageクラスの定義
abstract class Beverage {
    // テンプレートメソッド：処理の流れを定義
    final void prepare() {
        boilWater();
        brew();
        pourInCup();
        addCondiments();
    }

    // boilWaterメソッドの定義
    void boilWater() {
        System.out.println("お湯を沸かす");
    }

    // pourInCupメソッドの定義
    void pourInCup() {
        System.out.println("カップに注ぐ");
    }
    abstract void brew();           // サブクラスが実装
    abstract void addCondiments();  // サブクラスが実装
}

// Teaクラスの定義
class Tea extends Beverage {
    @Override
    void brew() {
        System.out.println("茶葉を蒸らす");
    }
    @Override
    void addCondiments() {
        System.out.println("レモンを添える");
    }
}

// Mainクラスの定義
public class Main {
    public static void main(String[] args) {
        Beverage tea = new Tea();
        tea.prepare();
    }
}

