// Printableインターフェースの定義
interface Printable {
    void print();  // public abstractが暗黙的に付く
}

// Resizableインターフェースの定義
interface Resizable {
    void resize(int width, int height);
}

// 複数のインターフェースを実装
// Documentクラスの定義
class Document implements Printable, Resizable {
    String content;

    Document(String content) {
        this.content = content;
    }
    @Override
    // printメソッドの定義
    public void print() {
        System.out.println("印刷: " + content);
    }
    @Override
    // resizeメソッドの定義
    public void resize(int width, int height) {
        System.out.println("サイズ変更: " + width + "x" + height);
    }
}

// Mainクラスの定義
public class Main {
    public static void main(String[] args) {
        Document doc = new Document("レポート");
        doc.print();                // 印刷: レポート
        doc.resize(800, 600);       // サイズ変更: 800x600

        Printable p = doc;          // インターフェース型で参照
        p.print();                  // 印刷: レポート
    }
}

