// Measurableインターフェースの定義
interface Measurable {
    double getMeasure();
}

// Shapeクラスの定義
abstract class Shape implements Measurable {
    String name;

    Shape(String name) {
        this.name = name;
    }
    abstract double area();

    @Override
    // getMeasureメソッドの定義
    public double getMeasure() {
        return area();  // 面積を測定値として返す
    }
    @Override
    // toStringメソッドの定義
    public String toString() {
        return name + "(面積: " + area() + ")";
    }
}

// Rectangleクラスの定義
class Rectangle extends Shape {
    double width, height;

    Rectangle(double w, double h) {
        super("長方形");
        this.width = w;
        this.height = h;
    }
    @Override
    double area() {
        return width * height;
    }
}

// Mainクラスの定義
public class Main {
    public static void main(String[] args) {
        Shape s = new Rectangle(3, 4);
        System.out.println(s);               // 長方形(面積: 12.0)
        System.out.println(s.getMeasure());   // 12.0
    }
}

